import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How does a UK mortgage work?", a: "A UK repayment mortgage is paid back monthly over a set term. Each payment includes interest and part of the loan balance until the mortgage is fully repaid." },
  { q: "What is LTV in a UK mortgage?", a: "LTV means loan-to-value. It compares the mortgage amount to the property value. A lower LTV usually means a larger deposit and may unlock better rates." },
  { q: "What is stamp duty?", a: "Stamp Duty Land Tax is a tax paid when buying property in England and Northern Ireland above certain thresholds. Scotland and Wales use separate property tax systems." },
  { q: "What is the difference between fixed rate and tracker mortgages in the UK?", a: "A fixed rate mortgage keeps the same interest rate for a set period. A tracker mortgage moves with a benchmark rate, usually the Bank of England base rate plus a margin." },
  { q: "What is a help-to-buy ISA?", a: "A Help to Buy ISA was a UK savings product for first-time buyers. New accounts are closed, but existing account holders may still be able to claim the government bonus if eligible." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const gbp = (v: number, d = 0) => new Intl.NumberFormat("en-GB", { style: "currency", currency: "GBP", maximumFractionDigits: d }).format(Number.isFinite(v) ? v : 0);
function payment(principal: number, rate: number, years: number) {
  const r = rate / 100 / 12;
  const n = years * 12;
  if (principal <= 0 || n <= 0) return 0;
  return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n));
}

export default function MortgageCalculatorUK() {
  const [price, setPrice] = useState(300000);
  const [deposit, setDeposit] = useState(45000);
  const [term, setTerm] = useState(25);
  const [rate, setRate] = useState(5);
  const result = useMemo(() => {
    const loan = Math.max(0, price - deposit);
    const monthly = payment(loan, rate, term);
    const total = monthly * term * 12;
    return { loan, monthly, total, interest: total - loan, ltv: price > 0 ? loan / price * 100 : 0 };
  }, [price, deposit, term, rate]);
  const rows = [150000, 200000, 300000, 400000, 500000].map((p) => {
    const loan = p * 0.85;
    const at5 = payment(loan, 5, 25);
    return [p, payment(loan, 4, 25), at5, payment(loan, 6, 25), at5 * 300 - loan] as const;
  });

  return (
    <>
      <SEOHead title="Free UK Mortgage Calculator Online - Calculate UK Mortgage Repayments Instantly | CalcHive" description="Free online UK mortgage calculator. Calculate monthly mortgage repayments, total interest and LTV ratio for any UK property price, deposit and rate instantly. 100% free, no signup required." canonical="/mortgage-calculator-uk" keywords="free UK mortgage calculator, UK mortgage repayment calculator free, British mortgage calculator free online, calculate UK mortgage free, mortgage calculator UK free" category="Financial Calculators" breadcrumbName="Free UK Mortgage Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free UK Mortgage Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate UK repayment mortgage cost, total interest, and loan-to-value ratio.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Property price</label><input type="number" value={price} onChange={(e) => setPrice(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Deposit amount</label><input type="number" value={deposit} onChange={(e) => setDeposit(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Mortgage term years</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Repayment</p><p className="text-5xl sm:text-6xl font-black text-white">{gbp(result.monthly, 2)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total repayment</p><p className="text-lg font-extrabold text-foreground">{gbp(result.total)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{gbp(result.interest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">LTV ratio</p><p className="text-lg font-extrabold text-foreground">{result.ltv.toFixed(1)}%</p></div></div></section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate UK Mortgage Repayments for Free</h2><p className="text-muted-foreground leading-relaxed">Subtract your deposit from the property price, then amortise the mortgage balance over the chosen term using the annual interest rate.</p><h2 className="text-2xl font-bold text-foreground">How Deposit and LTV Affect Your UK Mortgage Rate</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">UK Mortgage Monthly Repayment by Property Price and Rate</caption><thead className="bg-muted/60"><tr>{["Property Price", "4% Rate 25yr", "5% Rate 25yr", "6% Rate 25yr", "Total Interest at 5%"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}><td className="py-2.5 px-3 font-semibold">{gbp(r[0])}</td><td className="py-2.5 px-3">{gbp(r[1], 2)}</td><td className="py-2.5 px-3">{gbp(r[2], 2)}</td><td className="py-2.5 px-3">{gbp(r[3], 2)}</td><td className="py-2.5 px-3">{gbp(r[4])}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free British Mortgage Calculator for UK Home Buyers</h2><p className="text-muted-foreground leading-relaxed">Use this estimate before comparing lender offers, product fees, stamp duty, and insurance costs.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/mortgage-calculator-uk" headingLevel="h3" />
      </main>
    </>
  );
}


